`),$h=["#version 300 es","precision highp float;","precision highp int;","","in vec3 a_position;","in float a_size;","in vec4 a_color;","","uniform mat4 u_viewMatrix;","uniform mat4 u_projectionMatrix;","uniform mat4 u_modelMatrix;","uniform float u_defaultSize;","uniform vec4 u_defaultColor;","uniform bool u_hasPerVertexColor;","uniform bool u_hasPerVertexSize;","uniform bool u_sizeAttenuation;","uniform int u_pointStyle;","uniform float u_viewportHeight;","uniform float u_minPixelSize;","uniform float u_maxPixelSize;","","// Fog","uniform int u_hasFog;","uniform float u_fogDensity;","","out vec4 v_color;","out float v_fogFactor;","out float v_pointSize;","","void main() {","    vec4 worldPos = u_modelMatrix * vec4(a_position, 1.0);","    vec4 viewPos = u_viewMatrix * worldPos;","    gl_Position = u_projectionMatrix * viewPos;","","    float size = u_hasPerVertexSize ? a_size : u_defaultSize;","    float pixelSize;","    if (u_sizeAttenuation) {","        pixelSize = max(size * (u_viewportHeight * 0.5) / max(-viewPos.z, 0.001), 1.0);","    } else {","        pixelSize = max(size, 1.0);","    }","    float minPixelSize = max(u_minPixelSize, 0.0);","    if (minPixelSize > 0.0) {","        pixelSize = max(pixelSize, minPixelSize);","    }","    if (u_maxPixelSize > 0.0) {","        pixelSize = min(pixelSize, u_maxPixelSize);","    }","    gl_PointSize = pixelSize;","    v_pointSize = gl_PointSize;","","    v_color = u_hasPerVertexColor ? a_color : u_defaultColor;","","    // Exponential fog","    if (u_hasFog != 0) {","        float dist = length(viewPos.xyz);","        v_fogFactor = exp(-u_fogDensity * u_fogDensity * dist * dist);","        v_fogFactor = clamp(v_fogFactor, 0.0, 1.0);","    } else {","        v_fogFactor = 1.0;","    }","}"].join(`
